                                        <div class="underline-kamand-circle"></div>
                                    </div>
                                    @php
                                        $variant = $product->productVariant->first();
                                        $price = $variant->first()?->main_price ?? 0;
                                        $discount = $variant->first()?->discount_percent ?? 0;
                                        $final_price = $discount ? $price - ($price * $discount / 100) : $price;
                                    @endphp

                                    <div class="single-product-kamand-item-bottom-header-price"
                                         data-product-id="{{ $product->id }}">

                                        @if($discount)

                                            <div class="single-product-kamand-item-bottom-header-price-regular">
                                                <div
                                                    class="single-product-kamand-item-bottom-header-price-regular-number">
                                                    {{ number_format($price) }}
                                                </div>

                                                <div
                                                    class="single-product-kamand-item-bottom-header-price-regular-discount">
                                                    %{{ $discount }}
                                                </div>
                                            </div>

                                            <div class="single-product-kamand-item-bottom-header-price-sales-off">
                                                <div
                                                    class="single-product-kamand-item-bottom-header-price-sales-off-shape"></div>
                                                <span
                                                    class="single-product-kamand-item-bottom-header-price-sales-off-number">
                                                    {{ number_format($final_price) }}
                                                </span>
                                                <span
                                                    class="single-product-kamand-item-bottom-header-price-sales-off-symbol">تومان</span>
                                            </div>

                                        @else

                                            <div class="single-product-kamand-item-bottom-header-price-sales-off">
                                                <div
                                                    class="single-product-kamand-item-bottom-header-price-sales-off-shape"></div>
                                                <span
                                                    class="single-product-kamand-item-bottom-header-price-sales-off-number d-flex justify-content-end">
                                                    {{ number_format($price) }}
                                                </span>
                                                <span
                                                    class="single-product-kamand-item-bottom-header-price-sales-off-symbol">تومان</span>
                                            </div>

                                        @endif

                                    </div>

                                    <script>
                                        document.addEventListener('DOMContentLoaded', function () {
                                            const wrapper = document.querySelector('.single-product-kamand-item-bottom-header-price');
                                            const form = document.querySelector('form.variations_form');

                                            if (form && wrapper) {
                                                jQuery(form).on('found_variation', function (event, variation) {
                                                    const regular = variation.display_regular_price;
                                                    const sale = variation.display_price;
                                                    const discount = regular > sale ? Math.round(((regular - sale) / regular) * 100) : 0;

                                                    const regularBox = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-regular');
                                                    const regularNumber = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-regular-number');
                                                    const discountEl = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-regular-discount');
                                                    const saleNumber = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-sales-off-number');

                                                    if (discount > 0) {
                                                        regularBox.style.display = 'flex';
                                                        regularNumber.textContent = regular.toLocaleString();
                                                        discountEl.textContent = '%' + discount;
                                                    } else {
                                                        regularBox.style.display = 'none';
                                                    }

                                                    saleNumber.textContent = sale.toLocaleString();
                                                });

                                                jQuery(form).on('reset_data', function () {
                                                    const regularBox = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-regular');
                                                    const regularNumber = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-regular-number');
                                                    const discountEl = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-regular-discount');
                                                    const saleNumber = wrapper.querySelector('.single-product-kamand-item-bottom-header-price-sales-off-number');

                                                    regularBox.style.display = 'flex';
                                                    regularNumber.textContent = '56,000,000';
                                                    discountEl.textContent = '%54';

                                                    saleNumber.textContent = '26,000,000';
                                                });
                                            }
                                        });
                                    </script>
                                </div>
                            </div>
                        </div>
                    @endforeach
                </div>
